+impl MetaballsCanvasAdapter {
+    fn ensure_active_indices(&mut self, step: usize, len: usize) {
+        if self.active_step == step && self.active_len == len {
+            return;
+        }
+        self.active_indices.clear();
+        for i in 0..len {
+            if i % step == 0 {
+                self.active_indices.push(i);
+            }
+        }
+        self.active_step = step;
+        self.active_len = len;
+    }
+}
